// Turntable - Extract Data from Confirmation Message
const items = $input.all();
const output = [];

for (const item of items) {
  const text = item.json.output || item.json.text || '';

  // 1. Email
  const emailRegex = /([a-zA-Z0-9._-]+@[a-zA-Z0-9._-]+\.[a-zA-Z0-9_-]+)/gi;
  const emailMatches = text.match(emailRegex);
  const email = emailMatches && emailMatches.length > 0 ? emailMatches[0] : null;

  // 2. Nombre — emoji format: "👤 Nombre Apellido" OR label format fallback
  const nombreMatch = text.match(/\u{1F464}\s*([^\n]+)/u)
                   || text.match(/Nombre:\s*([^\n]+)/i);
  const nombre = nombreMatch ? nombreMatch[1].trim() : 'Cliente';

  // 3. Cedula — emoji format: "🆔 1234567890"
  const cedulaMatch = text.match(/\u{1F194}\s*([^\n]+)/u)
                   || text.match(/C[e\u00e9]dula:\s*([^\n]+)/i);
  const cedula = cedulaMatch ? cedulaMatch[1].trim() : '';

  // 4. Telefono — emoji format: "📱 3003224808" (first occurrence = client phone)
  const telefonoMatch = text.match(/Tel[e\u00e9]fono:\s*([^\n]+)/i)
                     || text.match(/\u{1F4F1}\s*([^\n]+)/u);
  const telefono = telefonoMatch ? telefonoMatch[1].trim() : '';

  // 5. Sala — emoji format: "🏠 Sala Circuito 🎚️"
  const salaMatch = text.match(/\u{1F3E0}\s*([^\n]+)/u)
                 || text.match(/Sala:\s*([^\n]+)/i);
  const sala = salaMatch ? salaMatch[1].trim() : '';

  // 6. Setup — emoji format: "🎛️ Setup description"
  const setupMatch = text.match(/\u{1F39B}\uFE0F?\s*([^\n]+)/u)
                  || text.match(/Setup:\s*([^\n]+)/i);
  const setup = setupMatch ? setupMatch[1].trim() : '';

  // 7. Fecha — emoji format: "📅 Sábado 25 de abril de 2026"
  const fechaCitaMatch = text.match(/\u{1F4C5}\s*(?:Fecha:\s*)?([^\n]+)/iu);
  const fecha_cita = fechaCitaMatch ? fechaCitaMatch[1].trim() : '';

  // 8. Hora — emoji format: "🕐 2:00pm"
  const horaMatch = text.match(/\u{1F550}\s*([^\n]+)/u)
                 || text.match(/Hora:\s*([^\n]+)/i);
  const hora = horaMatch ? horaMatch[1].trim() : '';

  // 9. Duracion en horas — emoji format: "⏱️ 3 horas"
  const duracionMatch = text.match(/\u{23F1}\uFE0F?\s*(\d+)/u)
                     || text.match(/Duraci[o\u00f3]n:\s*(\d+)/i);
  const num_horas = duracionMatch ? parseInt(duracionMatch[1]) : 1;

  // 10. Precio total — emoji format: "💰 Total: $60,000 COP" OR "Valor Total:"
  const precioMatch = text.match(/\u{1F4B0}\s*Total:\s*\$\s*([\d.,]+)/u)
                   || text.match(/Valor Total:\s*\$\s*([\d.,]+)/i);
  const precio = precioMatch ? precioMatch[1].replace(/[.,]/g, '') : '';

  // --- Calcular fecha_inicio y fecha_fin con offset Bogota -05:00 ---
  let fecha_inicio = null;
  let fecha_fin = null;

  if (fecha_cita && hora) {
    try {
      const meses = {
        'enero':'01','febrero':'02','marzo':'03','abril':'04',
        'mayo':'05','junio':'06','julio':'07','agosto':'08',
        'septiembre':'09','octubre':'10','noviembre':'11','diciembre':'12'
      };
      const fechaLimpia = fecha_cita.toLowerCase();
      const diaMatch = fechaLimpia.match(/(\d{1,2})/);
      const anioMatch = fechaLimpia.match(/(\d{4})/);
      let mesNumero = '01';
      for (const mes in meses) {
        if (fechaLimpia.includes(mes)) { mesNumero = meses[mes]; break; }
      }
      if (diaMatch && anioMatch) {
        const dia = diaMatch[0].padStart(2, '0');
        const anio = anioMatch[0];
        const horaPartes = hora.match(/\d+/g);
        if (horaPartes) {
          let horas = parseInt(horaPartes[0]);
          let minutos = horaPartes[1] || '00';
          if (hora.toLowerCase().includes('pm') && horas < 12) horas += 12;
          if (hora.toLowerCase().includes('am') && horas === 12) horas = 0;
          const horaStr = horas.toString().padStart(2, '0');
          const minStr = minutos.toString().padStart(2, '0');
          const st = `${anio}-${mesNumero}-${dia}T${horaStr}:${minStr}:00-05:00`;
          const dateObj = new Date(st);
          if (!isNaN(dateObj.getTime())) {
            fecha_inicio = dateObj.toISOString();
            fecha_fin = new Date(dateObj.getTime() + num_horas * 3600000).toISOString();
          }
        }
      }
    } catch(e) { console.error('date parse error', e); }
  }

  output.push({ json: {
    email, nombre, cedula, telefono,
    sala, setup, num_horas,
    fecha_cita, hora, fecha_inicio, fecha_fin,
    precio,
    // Strip internal system tags so they never appear in the WhatsApp message
    textoCompleto: (() => {
      const cleaned = text
        .replace(/^RESERVA CONFIRMADA\s*\n*/i, '')
        .replace(/^RESERVA REAGENDADA\s*\n*/i, '')
        .replace(/^CANCELAR RESERVA\s*\n*/i, '')
        .trim();
      // Guarantee the payment warning is always present for RESERVA CONFIRMADA
      const isConfirmacion = /^RESERVA CONFIRMADA/i.test(text);
      const hasWarning = /sin el pago|no est. reservada|anticipo/i.test(cleaned);
      if (isConfirmacion && !hasWarning) {
        return cleaned + '\n\n━━━━━━━━━━━━━━━━━━━━\n'
          + '⚠️ Recuerda: tu sala NO queda bloqueada sin el anticipo del 50%.\n'
          + 'Sin el pago, el horario puede quedar disponible para otro cliente.';
      }
      return cleaned;
    })()
  }});
}

return output;

const chatwootData = $input.first().json.body;
const phoneRaw = chatwootData.sender?.phone_number || '';
const content = chatwootData.content || '';

if (!content.trim() && !(chatwootData.attachments && chatwootData.attachments.length > 0)) {
  throw new Error('Mensaje vacio recibido de Chatwoot');
}

const now = new Date();
const bogotaOffsetMs = 5 * 60 * 60 * 1000;
const nowBogota = new Date(now.getTime() - bogotaOffsetMs);
const pad = (n) => String(n).padStart(2, '0');
const todayBogota = `${nowBogota.getFullYear()}-${pad(nowBogota.getMonth()+1)}-${pad(nowBogota.getDate())}`;
const nowBogotaISO = `${todayBogota}T${pad(nowBogota.getHours())}:${pad(nowBogota.getMinutes())}:00-05:00`;
const DAYS_ES = ['domingo','lunes','martes','miercoles','jueves','viernes','sabado'];
const MONTHS_ES = ['enero','febrero','marzo','abril','mayo','junio','julio','agosto','septiembre','octubre','noviembre','diciembre'];
const dayName = DAYS_ES[nowBogota.getDay()];
const monthName = MONTHS_ES[nowBogota.getMonth()];
const todayFullBogota = `${dayName} ${nowBogota.getDate()} de ${monthName} de ${nowBogota.getFullYear()}`;

return [{
  json: {
    chatInput: content,
    input: content,
    message: content,
    today_bogota: todayBogota,
    now_bogota_iso: nowBogotaISO,
    today_full_bogota: todayFullBogota,
    timezone: 'America/Bogota',
    sessionKey: phoneRaw,
    from: phoneRaw,
    conversationId: chatwootData.conversation?.id,
    accountId: chatwootData.account?.id,
    messageSid: chatwootData.id,
    timestamp: new Date().toISOString()
  }
}];

const inputItems = $input.all();
if (!inputItems || inputItems.length === 0) {
  throw new Error('No se recibieron datos de Extraer Data.');
}
const cortes = inputItems.length;
let mejorItem = inputItems[0];
let maxCampos = 0;
for (const item of inputItems) {
  const campos = Object.values(item.json).filter(v => v !== '' && v !== null && v !== undefined && v !== 'Cliente').length;
  if (campos > maxCampos) { maxCampos = campos; mejorItem = item; }
}
const dataToKeep = mejorItem.json;
let mensaje = '';
try {
  const cnd = $('Code in JavaScript').all();
  if (cnd && cnd.length > 0) mensaje = cnd[0].json.textoCompleto || cnd[0].json.output || '';
} catch (e) {}
let conversationId = '';
let from = '';
try {
