// Turntable - Client Memory: Pre-fetch client data
// Triggered by Unificar LH (always has 1 item)
// Reads Sheets data from Buscar Cliente Existente (may be empty for new clients)
const allRows = $('Buscar Cliente Existente').all();
const codeData = $input.first().json;
const clientPhone = String(codeData.from || '');

const normalizePhone = (phone) => {
  const str = String(phone == null ? '' : phone);
  const digits = str.replace(/\D/g, '');
  return digits.slice(-10);
};

const clientPhoneNorm = normalizePhone(clientPhone);

const matchingRows = [];
if (clientPhoneNorm && clientPhoneNorm.length >= 7) {
  for (const row of allRows) {
    const rowPhone = normalizePhone(row.json.Telefono);
    if (rowPhone && rowPhone === clientPhoneNorm) {
      matchingRows.push(row.json);
    }
  }
}

let clienteContext = '';

if (matchingRows.length > 0) {
  matchingRows.sort((a, b) => String(b.Timestamp || '').localeCompare(String(a.Timestamp || '')));
  const latest = matchingRows[0];
  const totalVisitas = matchingRows.length;

  const safe = (val) => {
    if (val == null || val === '') return 'No disponible';
    return String(val);
  };

  clienteContext = `## DATOS DEL CLIENTE ACTUAL (RECUPERADOS DEL HISTORIAL)

CLIENTE EXISTENTE - Ha reservado en Turntable Dealer ${totalVisitas} vez/veces.

Datos personales registrados:
- Nombre Completo: ${safe(latest.Nombre_Completo)}
- Cedula: ${safe(latest.Cedula)}
- Email: ${safe(latest.email)}
- Telefono: ${safe(latest.Telefono)}

Ultima reserva registrada:
- Fecha: ${safe(latest.Fecha_Cita)}
- Hora: ${safe(latest.Hora)}
- Sala: ${safe(latest.Sala)}
- Setup: ${safe(latest.Setup)}
- Num Horas: ${safe(latest.Num_Horas)}
- Precio: ${safe(latest.Precio)}
- Estado: ${safe(latest.Estado)}

Total de visitas/reservas: ${totalVisitas}`;

