    clienteContext += '\n\nHistorial de reservas (mas recientes primero):';
    for (let i = 0; i < Math.min(matchingRows.length, 5); i++) {
      const row = matchingRows[i];
      clienteContext += `\n- ${safe(row.Fecha_Cita)} | ${safe(row.Sala)} | ${safe(row.Setup)} | Estado: ${safe(row.Estado)}`;
    }
  }

  clienteContext += `

INSTRUCCION CRITICA: Ya tienes TODOS los datos de este cliente. NO vuelvas a pedir nombre, cedula, email, telefono, fecha de nacimiento ni direccion. Usa estos datos directamente cuando llegue el momento de la confirmacion. Saluda al cliente por su nombre de forma personalizada.`;

} else {
  clienteContext = `## DATOS DEL CLIENTE ACTUAL

CLIENTE NUEVO - No hay historial previo para este numero de telefono.
Procede a recolectar todos los datos requeridos segun el flujo conversacional.`;
}

return [{
  json: {
    ...codeData,
    clienteContext
  }
}];

