const SLOT_MIN        = 30;   // resolución de detección
const MIN_SESSION_MIN = 60;   // sesión mínima (1 hora)
const OPEN_MIN        = 10 * 60;
const CLOSE_MIN       = 22 * 60;  // última hora de FIN (sesión 21:00-22:00)
