// Marca como ocupados los minutos [evStart-MIN_SESSION_MIN, evEnd)
// así la ventana libre ya incorpora el buffer antes del evento.
function getBusyMinutes(dateStr, events) {
  const busy = new Set();
  const dayStartMs = new Date(dateStr + 'T00:00:00-05:00').getTime();
  for (const ev of events) {
    if (!ev.start) continue;
    if (!ev.start.dateTime) {
      // evento de día completo (ej: "No Disponible")
      if ((ev.start.date || '').slice(0, 10) === dateStr)
        for (let m = OPEN_MIN; m < CLOSE_MIN; m += SLOT_MIN) busy.add(m);
      continue;
    }
    const sMs  = new Date(ev.start.dateTime).getTime();
    const eMs  = new Date(ev.end ? ev.end.dateTime : ev.start.dateTime).getTime();
    const sMin = Math.round((sMs - dayStartMs) / 60000);
    const eMin = Math.round((eMs - dayStartMs) / 60000);
    // Buffer hacia atrás: bloquear desde sMin-MIN_SESSION_MIN para que
    // la ventana libre ya NO incluya inicios que llegarían a solaparse.
    const bufStart = Math.max(OPEN_MIN, sMin - MIN_SESSION_MIN);
    for (let m = bufStart; m < eMin; m += SLOT_MIN) busy.add(m);
  }
  return busy;
}

function getFreeWindows(dateStr, dayOffset, busySet) {
  const minStart = dayOffset === 0
    ? Math.ceil(currentMin / SLOT_MIN) * SLOT_MIN
    : OPEN_MIN;
  const effectiveOpen = Math.max(OPEN_MIN, minStart);
  const windows = [];
  let winStart = null;
  for (let m = effectiveOpen; m < CLOSE_MIN; m += SLOT_MIN) {
    const free = !busySet.has(m);
    if (free  && winStart === null) winStart = m;
    if (!free && winStart !== null) { windows.push([winStart, m]); winStart = null; }
  }
  if (winStart !== null) windows.push([winStart, CLOSE_MIN]);
  return windows;
}

function toHHMM(m) { return pad(Math.floor(m/60)) + ':' + pad(m%60); }
function durStr(mins) {
  const h = Math.floor(mins/60), m = mins%60;
  return h > 0 ? (m > 0 ? `${h}h${m}m` : `${h}h`) : `${m}m`;
}

