  if (hm) { curDate = hm[1]; continue; }
  if (curDate && line.startsWith('  ')) {
    tableMap[curDate] = line.trim();
    curDate = null;
  }
}

const DIAS_ES  = ['domingo','lunes','martes','miércoles','jueves','viernes','sábado'];
const MESES_ES = ['enero','febrero','marzo','abril','mayo','junio','julio','agosto','septiembre','octubre','noviembre','diciembre'];

function toMinutes(hhmm) {
  const [h, m] = hhmm.split(':').map(Number);
  return h * 60 + m;
}
function fromMinutes(min) {
  return `${String(Math.floor(min/60)).padStart(2,'0')}:${String(min%60).padStart(2,'0')}`;
}
function formatDateLabel(ds) {
  const d = new Date(ds + 'T12:00:00Z');
  const dow = DIAS_ES[d.getUTCDay()];
  return `${dow.charAt(0).toUpperCase()+dow.slice(1)} ${d.getUTCDate()} de ${MESES_ES[d.getUTCMonth()]}`;
}
function getSlotsFromWindows(windowsStr) {
  if (!windowsStr || windowsStr === 'sin disponibilidad') return [];
  const slots = [];
  for (const part of windowsStr.split('|')) {
    const m = part.trim().match(/(\d{2}:\d{2})→(\d{2}:\d{2})/);
    if (!m) continue;
    const start = toMinutes(m[1]);
    const end   = toMinutes(m[2]);
    for (let t = start; t < end; t += SLOT_DISP) {
      slots.push(fromMinutes(t));
    }
  }
  return slots;
}
function formatSlotLines(slots) {
  return slots.slice(0, 8).map(s => `🎧 ${s}`).join('\n');
}
function findNextAvailableDays(fromDate, count = 3) {
  const now = new Date(Date.now() - 5 * 3600000);
  const todayStr = `${now.getUTCFullYear()}-${String(now.getUTCMonth()+1).padStart(2,'0')}-${String(now.getUTCDate()).padStart(2,'0')}`;
  const base = fromDate > todayStr ? fromDate : todayStr;
  const results = [];
  for (const ds of Object.keys(tableMap).sort()) {
    if (ds < base) continue;
    const slots = getSlotsFromWindows(tableMap[ds]);
    if (slots.length > 0) {
      results.push({ date: ds, label: formatDateLabel(ds), slots });
      if (results.length >= count) break;
    }
  }
  return results;
}

const processed = output.replace(
