const TOKEN = 'AoeU3jPUwbECJgDTp6cW8wrs';
const BASE = 'http://sinapsio_landing_chatwoot:3000/api/v1';
const HDR = {'api_access_token': TOKEN, 'Content-Type': 'application/json'};

// 1. Find or create owner contact
let contactId = null;
try {
  const s = await $helpers.httpRequest({method:'GET', url:`${BASE}/accounts/${accountId}/contacts/search?q=${OWNER}&include_contacts=true`, headers: HDR});
  const contacts = s.payload?.contacts || s.contacts || [];
  if (contacts.length > 0) contactId = contacts[0].id;
} catch(e) {}

if (!contactId) {
  try {
    const c = await $helpers.httpRequest({method:'POST', url:`${BASE}/accounts/${accountId}/contacts`, headers: HDR, body: JSON.stringify({name:'Dueño Turntable', phone_number: OWNER})});
    contactId = c.id;
  } catch(e) {}
}
if (!contactId) return [{json: {ok: false, error: 'no contact'}}];

// 2. Get inbox_id from client conversation
let inboxId = null;
try {
  const cv = await $helpers.httpRequest({method:'GET', url:`${BASE}/accounts/${accountId}/conversations/${bd.conversationId}`, headers: HDR});
  inboxId = cv.inbox_id;
} catch(e) {}

// 3. Create new conversation with owner
let ownerConvId = null;
try {
  const nc = await $helpers.httpRequest({method:'POST', url:`${BASE}/accounts/${accountId}/conversations`, headers: HDR, body: JSON.stringify({inbox_id: inboxId, contact_id: contactId, additional_attributes: {}})});
  ownerConvId = nc.id;
} catch(e) {}
if (!ownerConvId) return [{json: {ok: false, error: 'no conv'}}];

// 4. Send message
await $helpers.httpRequest({method:'POST', url:`${BASE}/accounts/${accountId}/conversations/${ownerConvId}/messages`, headers: HDR, body: JSON.stringify({content: bd.msgDueno, message_type:'outgoing', private: false})});

return [{json: {ok: true, ownerConvId, contactId}}];

