// Fallback: Redis miss → buscar en Sheets por teléfono + Estado=Pendiente Pago
const telefonoNorm = $('Verificar Comprobante TT').first().json.telefonoNorm; // últimos 10 dígitos

const rows = $input.all();

// Filtrar filas que coincidan con el teléfono (comparar últimos 10 dígitos)
const matching = rows.filter(r => {
  const tel = String(r.json.Telefono || '').replace(/\D/g,'');
  return tel.endsWith(telefonoNorm);
});

if (matching.length === 0) {
  // Sin coincidencia → emitir resultado nulo (mismo formato que Redis pipeline)
  return [{ json: { result: null } }];
}

// Tomar la más reciente (última fila que coincide)
const row = matching[matching.length - 1].json;

const booking = {
  nombre:      row.Nombre_Completo || '',
  cedula:      row.Cedula          || '',
  telefono:    row.Telefono        || '',
  email:       row.email           || '',
  sala:        row.Sala            || '',
  setup:       row.Setup           || '',
  fecha_cita:  row.Fecha_Cita      || '',
  hora:        row.Hora            || '',
  num_horas:   row.Numero_Horas    || '',
  precio:      row.Precio          || 0,
  fecha_inicio: row.Fecha_Inicio_ISO || '',
  fecha_fin:    row.Fecha_Fin_ISO   || '',
  monto_anticipo: row.Monto_Anticipo || Math.round(Number(row.Precio||0)/2)
};

// Emitir en el mismo formato que Redis pipeline response
return [{ json: { result: JSON.stringify(booking) } }];

const item = $input.first().json;
const output = item.output || '';

// Check if bot flagged escalation
const hasEscalar = output.trim().startsWith('ESCALAR');

// Strip the tag so WhatsApp message to client is clean
let cleanOutput = output;
if (hasEscalar) {
  cleanOutput = output.replace(/^ESCALAR\s*\n?/i, '').trim();
}

return [{ json: { ...item, output: cleanOutput, escalar: hasEscalar } }];
